using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Running;
using TextAnalysis;

BenchmarkRunner.Run<TextAnalyzerBenchmarks>();

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    // A non-trivial paragraph to exercise the methods
    private const string SampleText =
        "The quick brown fox jumps over the lazy dog. " +
        "A stitch in time saves nine, but a rolling stone gathers no moss. " +
        "To be or not to be that is the question whether tis nobler in the mind " +
        "to suffer the slings and arrows of outrageous fortune or to take arms " +
        "against a sea of troubles and by opposing end them. " +
        "All that glitters is not gold; not all those who wander are lost. " +
        "In the beginning was the word and the word was with God and the word was God.";

    [GlobalSetup]
    public void Setup()
    {
        _analyzer = new TextAnalyzer(SampleText);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

